class Playground {
    async run(inputs) {
        // Parse inputs
        const rawArr = inputs[0].split(',').map(x => parseInt(x.trim())).filter(x => !isNaN(x));
        // Ensure the array is sorted for Binary Search
        const arr = rawArr.sort((a, b) => a - b);
        const target = parseInt(inputs[1]);

        // Initialize slots
        await this.array_slot.init(arr);
        await this.vars_slot.init([
            ["low", 0],
            ["high", arr.length - 1],
            ["target", target]
        ]);

        let low = 0;
        let high = arr.length - 1;

        this.log(`Starting Binary Search for target: ${target}`);
        await this.await();

        while (low <= high) {
            const mid = Math.floor(low + (high - low) / 2);
            const midVal = this.array_slot.get(mid);

            // Update state visualization
            this.vars_slot.put("low", low);
            this.vars_slot.put("high", high);
            this.vars_slot.put("mid", mid);
            this.vars_slot.put("midValue", midVal);

            // Highlight the search range and the middle element
            // Reset highlights by highlighting full range with a neutral color first if needed,
            // but here we use specific colors for the active window.
            this.array_slot.highlightRange(0, arr.length - 1, "#2d2d2d"); // Dim others
            this.array_slot.highlightRange(low, high, "#ffb703"); // Current search space
            this.array_slot.highlight(mid, "#00e0ff"); // Current mid pivot

            this.log(`Checking middle index ${mid} (Value: ${midVal})`);
            await this.await();

            if (midVal === target) {
                this.log(`Success! Target ${target} found at index ${mid}.`);
                this.array_slot.highlight(mid, "#00f5a0"); // Success color
                await this.await();
                return mid;
            }

            if (midVal < target) {
                this.log(`${midVal} is less than ${target}. Narrowing search to the right half.`);
                low = mid + 1;
            } else {
                this.log(`${midVal} is greater than ${target}. Narrowing search to the left half.`);
                high = mid - 1;
            }

            this.vars_slot.put("low", low);
            this.vars_slot.put("high", high);
            await this.await();
        }

        this.log(`Target ${target} not found in the array.`);
        this.array_slot.highlightRange(0, arr.length - 1, "#ff4d4d"); // Error/Not found indicator
        return -1;
    }
}
